"""Kubernetes Provider for Agent Deployment"""

from typing import Dict, Any, Optional
from kubernetes import client, config
from kubernetes.client.rest import ApiException
import time


class KubernetesProvider:
    """Standard Kubernetes deployment provider"""

    def __init__(self):
        try:
            config.load_incluster_config()
        except config.ConfigException:
            config.load_kube_config()
        self.apps_v1 = client.AppsV1Api()
        self.core_v1 = client.CoreV1Api()

    def deploy_agent(self, config_dict: Dict[str, Any]) -> Dict[str, Any]:
        """Deploy agent as Kubernetes Deployment"""
        namespace = config_dict.get("namespace", "default")
        deployment_name = config_dict["agent_name"]
        image = config_dict.get("image", f"{deployment_name}:latest")
        port = config_dict.get("port", 8080)
        replicas = config_dict.get("replicas", 1)

        deployment = client.V1Deployment(
            api_version="apps/v1",
            kind="Deployment",
            metadata=client.V1ObjectMeta(name=deployment_name, namespace=namespace),
            spec=client.V1DeploymentSpec(
                replicas=replicas,
                selector=client.V1LabelSelector(match_labels={"app": deployment_name}),
                template=client.V1PodTemplateSpec(
                    metadata=client.V1ObjectMeta(labels={"app": deployment_name}),
                    spec=client.V1PodSpec(
                        containers=[
                            client.V1Container(
                                name=deployment_name,
                                image=image,
                                ports=[client.V1ContainerPort(container_port=port)],
                            )
                        ]
                    ),
                ),
            ),
        )

        result = self.apps_v1.create_namespaced_deployment(namespace=namespace, body=deployment)

        service = client.V1Service(
            api_version="v1",
            kind="Service",
            metadata=client.V1ObjectMeta(name=f"{deployment_name}-svc", namespace=namespace),
            spec=client.V1ServiceSpec(
                type="NodePort",
                selector={"app": deployment_name},
                ports=[client.V1ServicePort(port=port, target_port=port)],
            ),
        )

        self.core_v1.create_namespaced_service(namespace=namespace, body=service)

        return {
            "deployment_name": deployment_name,
            "namespace": namespace,
            "status": "deployed",
        }

    def wait_for_deployment_ready(self, deployment_name: str, namespace: str, timeout: int = 120):
        """Wait for deployment to be ready"""
        start_time = time.time()
        while time.time() - start_time < timeout:
            deployment = self.apps_v1.read_namespaced_deployment_status(
                name=deployment_name, namespace=namespace
            )
            if (
                deployment.status.ready_replicas
                and deployment.status.ready_replicas > 0
                and deployment.status.ready_replicas == deployment.status.replicas
            ):
                return
            time.sleep(2)
        raise TimeoutError(f"Deployment {deployment_name} not ready within {timeout}s")

    def delete_agent(self, deployment_name: str, namespace: str) -> Dict[str, Any]:
        """Delete agent deployment and service"""
        try:
            self.apps_v1.delete_namespaced_deployment(name=deployment_name, namespace=namespace)
        except ApiException as e:
            if e.status != 404:
                raise

        try:
            self.core_v1.delete_namespaced_service(
                name=f"{deployment_name}-svc", namespace=namespace
            )
        except ApiException as e:
            if e.status != 404:
                raise

        return {"status": "deleted", "deployment_name": deployment_name}

    def get_agent_status(self, deployment_name: str, namespace: str) -> Dict[str, Any]:
        """Get agent deployment status"""
        try:
            deployment = self.apps_v1.read_namespaced_deployment_status(
                name=deployment_name, namespace=namespace
            )
            pods = self.core_v1.list_namespaced_pod(
                namespace=namespace, label_selector=f"app={deployment_name}"
            )
            pod_statuses = [
                {
                    "name": pod.metadata.name,
                    "phase": pod.status.phase,
                    "ready": any(c.ready for c in pod.status.conditions or []),
                }
                for pod in pods.items
            ]
            return {
                "deployment_name": deployment_name,
                "namespace": namespace,
                "replicas": deployment.status.replicas,
                "ready_replicas": deployment.status.ready_replicas,
                "pods": pod_statuses,
            }
        except ApiException as e:
            if e.status == 404:
                return {"status": "not_found", "deployment_name": deployment_name}
            raise

