from typing import Dict, Any, Optional
from kubernetes import client, config
from kubernetes.client.rest import ApiException


class AgentCubeProvider:
    """AgentCube CRD provider for deploying AgentRuntime resources"""

    def __init__(self):
        try:
            config.load_incluster_config()
        except config.ConfigException:
            config.load_kube_config()
        self.custom_api = client.CustomObjectsApi()
        self.group = "runtime.agentcube.volcano.sh"
        self.version = "v1alpha1"

    def deploy_agent_runtime(self, config_dict: Dict[str, Any]) -> Dict[str, Any]:
        """Deploy agent as AgentRuntime CR"""
        namespace = config_dict.get("namespace", "default")
        agent_name = config_dict["agent_name"]
        image = config_dict.get("image", f"{agent_name}:latest")
        port = config_dict.get("port", 8080)

        agent_runtime = {
            "apiVersion": f"{self.group}/{self.version}",
            "kind": "AgentRuntime",
            "metadata": {
                "name": agent_name,
                "namespace": namespace,
            },
            "spec": {
                "ports": [{"port": port, "protocol": "TCP"}],
                "template": {
                    "sandboxTemplate": {
                        "containers": [
                            {
                                "name": agent_name,
                                "image": image,
                                "ports": [{"containerPort": port}],
                            }
                        ]
                    }
                },
                "sessionTimeout": "15m",
                "maxSessionDuration": "8h",
            },
        }

        try:
            self.custom_api.create_namespaced_custom_object(
                group=self.group,
                version=self.version,
                namespace=namespace,
                plural="agentruntimes",
                body=agent_runtime,
            )
        except ApiException as e:
            if e.status == 409:
                self.custom_api.replace_namespaced_custom_object(
                    group=self.group,
                    version=self.version,
                    namespace=namespace,
                    name=agent_name,
                    plural="agentruntimes",
                    body=agent_runtime,
                )
            else:
                raise

        return {
            "agent_name": agent_name,
            "namespace": namespace,
            "status": "deployed",
            "kind": "AgentRuntime",
        }

    def get_agent_runtime_status(self, name: str, namespace: str) -> Dict[str, Any]:
        """Get AgentRuntime CR status"""
        try:
            cr = self.custom_api.get_namespaced_custom_object(
                group=self.group,
                version=self.version,
                namespace=namespace,
                name=name,
                plural="agentruntimes",
            )
            return {
                "name": name,
                "namespace": namespace,
                "status": cr.get("status", {}),
                "phase": cr.get("status", {}).get("phase", "Unknown"),
            }
        except ApiException as e:
            if e.status == 404:
                return {"status": "not_found", "name": name}
            raise

    def delete_agent_runtime(self, name: str, namespace: str) -> Dict[str, Any]:
        """Delete AgentRuntime CR"""
        try:
            self.custom_api.delete_namespaced_custom_object(
                group=self.group,
                version=self.version,
                namespace=namespace,
                name=name,
                plural="agentruntimes",
            )
            return {"status": "deleted", "name": name}
        except ApiException as e:
            if e.status == 404:
                return {"status": "not_found", "name": name}
            raise

