from typing import Dict, Any
from agentcube.services.metadata_service import MetadataService
from agentcube.services.k8s_provider import KubernetesProvider
from agentcube.services.agentcube_provider import AgentCubeProvider


class StatusRuntime:
    """Status command implementation"""

    def __init__(self, provider: str = "k8s"):
        self.provider = provider
        self.metadata_service = MetadataService()
        if provider == "agentcube":
            self.status_provider = AgentCubeProvider()
        else:
            self.status_provider = KubernetesProvider()

    def get_status(self, workspace_path: str) -> Dict[str, Any]:
        """Get agent status"""
        try:
            metadata = self.metadata_service.load_metadata(workspace_path)
        except FileNotFoundError:
            return {"status": "not_packed"}

        if not metadata.agent_id:
            return {"status": "not_published", "agent_name": metadata.agent_name}

        if self.provider == "agentcube":
            result = self.status_provider.get_agent_runtime_status(
                name=metadata.agent_id, namespace="default"
            )
        else:
            result = self.status_provider.get_agent_status(
                deployment_name=metadata.agent_id, namespace="default"
            )

        return result

