import os
from typing import Tuple, Optional, Dict, Any
from agentcube.models.pack_models import AgentMetadata
from agentcube.services.metadata_service import MetadataService


class PackRuntime:
    """Pack command implementation"""

    def __init__(self, metadata_overrides: Optional[Dict[str, Any]] = None):
        self.metadata_overrides = metadata_overrides or {}
        self.metadata_service = MetadataService()

    def pack(self, workspace_path: str) -> Tuple[str, str]:
        """Pack agent source code"""
        if not os.path.exists(workspace_path):
            raise FileNotFoundError(f"Workspace not found: {workspace_path}")
        if not os.path.isdir(workspace_path):
            raise NotADirectoryError(f"Not a directory: {workspace_path}")

        language = self.metadata_overrides.get("language", "python")
        if language == "python":
            py_files = [f for f in os.listdir(workspace_path) if f.endswith(".py")]
            if not py_files:
                raise ValueError("No Python files found in workspace")
        elif language == "java":
            if not os.path.exists(os.path.join(workspace_path, "pom.xml")):
                raise ValueError("pom.xml not found for Java project")

        try:
            metadata = self.metadata_service.load_metadata(workspace_path)
        except FileNotFoundError:
            metadata = AgentMetadata(
                agent_name=self.metadata_overrides.get("agent_name", "my-agent"),
                language=language,
                entrypoint=self.metadata_overrides.get("entrypoint", "main.py"),
                port=self.metadata_overrides.get("port", 8080),
                build_mode=self.metadata_overrides.get("build_mode", "local"),
                version=self.metadata_overrides.get("version", "0.1.0"),
                description=self.metadata_overrides.get("description", ""),
            )

        for key, value in self.metadata_overrides.items():
            if hasattr(metadata, key) and value is not None:
                setattr(metadata, key, value)

        self.metadata_service.save_metadata(metadata, workspace_path)
        metadata_path = os.path.join(workspace_path, "agent_metadata.yaml")

        return metadata.agent_name, metadata_path

