from typing import Dict, Any, Optional
from agentcube.services.metadata_service import MetadataService
from agentcube.services.k8s_provider import KubernetesProvider
from agentcube.services.agentcube_provider import AgentCubeProvider


class PublishRuntime:
    """Publish command implementation"""

    def __init__(
        self,
        provider: str = "k8s",
        version: Optional[str] = None,
        image_url: Optional[str] = None,
        **kwargs,
    ):
        self.provider = provider
        self.version = version
        self.image_url = image_url
        self.metadata_service = MetadataService()
        if provider == "agentcube":
            self.deploy_provider = AgentCubeProvider()
        else:
            self.deploy_provider = KubernetesProvider()

    def publish(self, workspace_path: str) -> Dict[str, Any]:
        """Publish agent to cluster"""
        metadata = self.metadata_service.load_metadata(workspace_path)

        if self.version:
            metadata.version = self.version
            self.metadata_service.save_metadata(metadata, workspace_path)

        if self.image_url:
            image = self.image_url
        else:
            image = f"{metadata.agent_name}:{metadata.version}"

        config = {
            "agent_name": metadata.agent_name,
            "namespace": metadata.metadata.get("namespace", "default"),
            "image": image,
            "port": metadata.port,
        }

        if self.provider == "agentcube":
            if not metadata.router_url or not metadata.workload_manager_url:
                raise ValueError(
                    "router_url and workload_manager_url are required for AgentCube provider"
                )
            result = self.deploy_provider.deploy_agent_runtime(config)
        else:
            result = self.deploy_provider.deploy_agent(config)
            if hasattr(self.deploy_provider, "wait_for_deployment_ready"):
                self.deploy_provider.wait_for_deployment_ready(
                    deployment_name=metadata.agent_name, namespace=config["namespace"]
                )

        metadata.agent_id = result.get("agent_name") or result.get("deployment_name")
        metadata.status = "published"
        self.metadata_service.save_metadata(metadata, workspace_path)

        return {
            "agent_name": metadata.agent_name,
            "version": metadata.version,
            "status": "published",
            "provider": self.provider,
        }

