import requests
from typing import Dict, Any, Optional, List
from agentcube.services.metadata_service import MetadataService


class InvokeRuntime:
    """Invoke command implementation"""

    def __init__(self, provider: str = "k8s", headers: Optional[List[str]] = None):
        self.provider = provider
        self.custom_headers = {}
        if headers:
            for header in headers:
                if ":" in header:
                    key, value = header.split(":", 1)
                    self.custom_headers[key.strip()] = value.strip()
        self.metadata_service = MetadataService()

    def invoke(self, workspace_path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        """Invoke agent endpoint"""
        metadata = self.metadata_service.load_metadata(workspace_path)

        if self.provider == "agentcube" and metadata.agent_id:
            base_url = metadata.router_url or metadata.workload_manager_url
            if not base_url:
                raise ValueError("router_url or workload_manager_url required for AgentCube provider")
            namespace = "default"
            target_url = f"{base_url}/v1/namespaces/{namespace}/agent-runtimes/{metadata.agent_id}/invocations/"
        else:
            target_url = f"http://{metadata.agent_name}-svc:{metadata.port}"

        headers = {"Content-Type": "application/json"}
        headers.update(self.custom_headers)

        if metadata.session_id:
            headers["X-Agentcube-Session-Id"] = metadata.session_id

        response = requests.post(target_url, json=payload, headers=headers, timeout=120)
        response.raise_for_status()

        return response.json()

